import json
from solution import tokenize

test_cases = [
    {
        "name": "simple define",
        "input": "(define x 42)",
        "expected": [("LPAREN", "("), ("IDENTIFIER", "define"), ("IDENTIFIER", "x"), ("NUMBER", 42), ("RPAREN", ")")]
    },
    {
        "name": "negative number",
        "input": "(- 3)",
        "expected": [("LPAREN", "("), ("IDENTIFIER", "-"), ("NUMBER", 3), ("RPAREN", ")")]
    },
    {
        "name": "boolean and quote",
        "input": "'#t",
        "expected": [("QUOTE", "'"), ("BOOLEAN", True)]
    },
    {
        "name": "comment ignored",
        "input": "; this is a comment\n(+ 1 2)",
        "expected": [("LPAREN", "("), ("IDENTIFIER", "+"), ("NUMBER", 1), ("NUMBER", 2), ("RPAREN", ")")]
    },
    {
        "name": "float number",
        "input": "3.14",
        "expected": [("NUMBER", 3.14)]
    },
    {
        "name": "complex expression",
        "input": "(define (square x) (* x x))",
        "expected": [("LPAREN", "("), ("IDENTIFIER", "define"), ("LPAREN", "("), ("IDENTIFIER", "square"), ("IDENTIFIER", "x"), ("RPAREN", ")"), ("LPAREN", "("), ("IDENTIFIER", "*"), ("IDENTIFIER", "x"), ("IDENTIFIER", "x"), ("RPAREN", ")"), ("RPAREN", ")")]
    }
]

for tc in test_cases:
    try:
        result = tokenize(tc["input"])
        passed = result == tc["expected"]
        message = "" if passed else f"Expected {tc['expected']}, got {result}"
        print(json.dumps({"name": tc["name"], "passed": passed, "message": message, "expected": tc["expected"], "actual": result}))
    except Exception as e:
        print(json.dumps({"name": tc["name"], "passed": False, "message": str(e), "expected": tc["expected"], "actual": None}))
